INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('gdpr-q1', 'policy/gdpr', 'When did the GDPR become effective?', 'The GDPR became effective on May 25, 2018, after being adopted by the European Parliament and Council on April 14, 2016.', 0);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('gdpr-q2', 'policy/gdpr', 'What is the maximum fine for the most serious GDPR violations?', 'Up to 20 million euros or 4% of total worldwide annual turnover of the preceding financial year, whichever is higher.', 1);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('gdpr-q3', 'policy/gdpr', 'Under Article 6, what are the lawful bases for processing personal data?', 'Six grounds: explicit data subject consent, fulfilling contractual obligations, complying with legal requirements, protecting vital interests, performing public tasks, and pursuing legitimate interests unless overridden by data subject rights.', 2);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('gdpr-q4', 'policy/gdpr', 'What is the default minimum age for valid consent under GDPR, and how can it differ across member states?', '16 years old by default; member states have the option to lower the threshold to 13.', 3);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('gdpr-q5', 'policy/gdpr', 'How quickly must controllers notify supervisory authorities of a personal data breach?', 'Within 72 hours.', 4);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('p24-q1', 'news/paris-2024-olympics', 'When and where did the 2024 Summer Olympics take place?', 'In France from July 26 to August 11, 2024 (with certain events beginning on July 24); Paris was the host city, with events distributed across 16 other metropolitan French locations and surfing in Teahupo''o, Tahiti.', 0);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('p24-q2', 'news/paris-2024-olympics', 'How many athletes, events, and sports were featured?', '10,714 athletes competing across 329 events in 32 sports comprising 48 disciplines.', 1);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('p24-q3', 'news/paris-2024-olympics', 'Which countries topped the medal table by gold and how did they compare?', 'The United States and China tied for first on gold medals with 40 each; the U.S. won 126 total medals to China''s 91. It was the first time the two nations tied in gold.', 2);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('p24-q4', 'news/paris-2024-olympics', 'Which new sports debuted or returned at Paris 2024?', 'Breaking made its Olympic debut. Skateboarding, sport climbing, and surfing returned after debuting at the 2020 Games.', 3);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('p24-q5', 'news/paris-2024-olympics', 'What was unusual about the opening ceremony?', 'It departed from tradition by occurring outside a stadium: athletes paraded by boat along the Seine from Pont d''Austerlitz to Pont d''Iéna, with cultural performances at landmarks. The Olympic cauldron used LED lighting and aerosol jets rather than actual combustion for the first time.', 4);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('tcp-q1', 'policy/rfc-9293-tcp', 'What does RFC 9293 specify and what does it obsolete?', 'RFC 9293 specifies the Transmission Control Protocol (TCP); it consolidates and updates the TCP specification, replacing earlier RFCs including RFC 793, with corrections, clarifications, and updates accumulated over decades.', 0);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('tcp-q2', 'policy/rfc-9293-tcp', 'What guarantees does TCP provide to applications?', 'Reliable, in-order, byte-stream delivery between endpoints, with congestion control and flow control over the unreliable IP network layer.', 1);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('tcp-q3', 'policy/rfc-9293-tcp', 'What is the three-way handshake?', 'The connection establishment procedure where the initiator sends SYN, the responder replies with SYN-ACK, and the initiator confirms with ACK, synchronising sequence numbers in both directions.', 2);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('tcp-q4', 'policy/rfc-9293-tcp', 'How does TCP detect and recover from packet loss?', 'Through cumulative acknowledgements, retransmission timers, and selective retransmission; lost segments are detected via missing ACKs or timeouts and retransmitted.', 3);
INSERT INTO qsets (q_id, doc_id, question, reference, position) VALUES ('tcp-q5', 'policy/rfc-9293-tcp', 'What is congestion control in TCP and why does it matter?', 'TCP adjusts sending rate based on observed network conditions (slow start, congestion avoidance, fast retransmit, fast recovery) to prevent collapse of the shared network when many flows compete for bandwidth.', 4);
